led_button_control.ino<pre><code>// LED Blink with Button Control
// Pin definitions
const int buttonPin = 2;    // Push button connected to pin 2
const int ledPin = 13;      // LED connected to pin 13

// Variables
int buttonState = 0;        // Current button state

void setup() {
  pinMode(ledPin, OUTPUT);          // Set LED pin as output
  pinMode(buttonPin, INPUT_PULLUP); // Use internal pull-up resistor
}

void loop() {
  // Read the button state (LOW when pressed due to pull-up)
  buttonState = digitalRead(buttonPin);

  if (buttonState == LOW) {
    digitalWrite(ledPin, HIGH);  // Turn LED on
  } else {
    digitalWrite(ledPin, LOW);   // Turn LED off
  }
}
</code></pre>

Toggle Mode <p>Modify the code to toggle the LED state with each button press:</p> C++<pre><code>bool ledState = false;
bool lastButtonState = HIGH;

void loop() {
  bool currentButtonState = digitalRead(buttonPin);

  if (currentButtonState == LOW &amp;&amp; lastButtonState == HIGH) {
    ledState = !ledState;
    digitalWrite(ledPin, ledState);
    delay(50); // Debounce
  }
  lastButtonState = currentButtonState;
}
</code></pre>

